_sage_const_78 = Integer(78); _sage_const_8 = Integer(8); _sage_const_4 = Integer(4); _sage_const_0xF = Integer(0xF); _sage_const_0 = Integer(0); _sage_const_1 = Integer(1); _sage_const_6 = Integer(6); _sage_const_3 = Integer(3); _sage_const_16 = Integer(16); _sage_const_2 = Integer(2); _sage_const_2808 = Integer(2808)

