# ============================================================
# 10. Write CryptoMiniSat XOR-DIMACS
#
# CryptoMiniSat XOR syntax:
#
#       x lit1 lit2 ... 0
#
# represents an XOR constraint with RHS true.
#
# Therefore:
#
#       XOR(vars) = 1
#
# can be written directly.
#
# For:
#
#       XOR(vars) = 0
#
# negate exactly one literal:
#
#       XOR(~x1,x2,...)=1
# ============================================================


with open(CNF_FILE, "w") as fp:

    fp.write(
        "p cnf %d %d\n"
        % (
            NUM_BOOL_VARS,
            len(xor_equations)
        )
    )


    for variables, rhs in xor_equations:


        # -----------------------------------------------
        # Empty XOR
        # -----------------------------------------------

        if len(variables) == _sage_const_0 :

            if rhs == _sage_const_0 :

                # Tautological XOR:
                #
                # x XOR ~x = 1

                fp.write(
                    "x 1 -1 0\n"
                )

            else:

                # Contradiction

                fp.write(
                    "0\n"
                )

            continue


        literals = list(
            variables
        )


        # CryptoMiniSat XOR lines have implicit RHS = 1.
        #
        # Negating one variable toggles parity.

        if rhs == _sage_const_0 :

            literals[_sage_const_0 ] = -literals[_sage_const_0 ]


        fp.write(
            "x "
            + " ".join(
                str(x)
                for x in literals
            )
            + " 0\n"
        )


